import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";
import "./App.css";

function App() {
  const [data, setData] = useState("Brak danych");

  return (
    <div className="App">
      <header className="App-header">
        <h1>Czytnik kodów QR</h1>

        <Scanner
          onScan={(result) => setData(result[0]?.rawValue)}
          onError={(error) => console.error(error)}
          style={{ width: "300px" }}
        />

        <p><strong>Odczytany kod:</strong> {data}</p>
      </header>
    </div>
  );
}

export default App;
